// packages/database/src/db/schema/thread.ts
// Drizzle table: thread (generated by scripts/split-schema.ts)

import { createId } from '@paralleldrive/cuid2'
import {
  type AnyPgColumn,
  index,
  integer,
  jsonb,
  pgTable,
  text,
  threadStatus,
  timestamp,
  uniqueIndex,
} from './_shared'
import { Comment } from './comment'
import { EntityInstance } from './entity-instance'
import { Integration } from './integration'
import { Message } from './message'
import { Organization } from './organization'
import { User } from './user'

/** Drizzle table for thread */
export const Thread = pgTable(
  'Thread',
  {
    id: text()
      .$defaultFn(() => createId())
      .primaryKey()
      .notNull(),
    externalId: text(),
    subject: text().notNull(),
    organizationId: text()
      .notNull()
      .references((): AnyPgColumn => Organization.id, { onUpdate: 'cascade', onDelete: 'cascade' }),
    integrationId: text()
      .notNull()
      .references((): AnyPgColumn => Integration.id, { onUpdate: 'cascade', onDelete: 'cascade' }),
    assigneeId: text().references((): AnyPgColumn => User.id, {
      onUpdate: 'cascade',
      onDelete: 'set null',
    }),
    status: threadStatus().default('OPEN').notNull(),
    messageCount: integer().default(0).notNull(),
    participantCount: integer().default(0).notNull(),
    firstMessageAt: timestamp({ precision: 3 }),
    lastMessageAt: timestamp({ precision: 3 }),
    /** Denormalized: ID of the latest non-draft message in the thread */
    latestMessageId: text().references((): AnyPgColumn => Message.id, {
      onUpdate: 'cascade',
      onDelete: 'set null',
    }),
    /** Denormalized: ID of the latest non-deleted comment on the thread */
    latestCommentId: text().references((): AnyPgColumn => Comment.id, {
      onUpdate: 'cascade',
      onDelete: 'set null',
    }),
    /** Denormalized: Inbox EntityInstance this thread belongs to (via InboxIntegration) */
    inboxId: text().references((): AnyPgColumn => EntityInstance.id, {
      onUpdate: 'cascade',
      onDelete: 'set null',
    }),
    closedAt: timestamp({ precision: 3 }),
    repliedAt: timestamp({ precision: 3 }),
    waitingSince: timestamp({ precision: 3 }),
    createdAt: timestamp({ precision: 3 }).defaultNow().notNull(),
    metadata: jsonb(),
  },
  (table) => [
    uniqueIndex('Thread_integrationId_externalId_key').using(
      'btree',
      table.integrationId.asc().nullsLast(),
      table.externalId.asc().nullsLast()
    ),
    index('Thread_integrationId_idx').using('btree', table.integrationId.asc().nullsLast()),
    index('Thread_lastMessageAt_idx').using('btree', table.lastMessageAt.asc().nullsLast()),
    index('Thread_organizationId_assigneeId_status_idx').using(
      'btree',
      table.organizationId.asc().nullsLast(),
      table.assigneeId.asc().nullsLast(),
      table.status.asc().nullsLast()
    ),
    index('Thread_organizationId_createdAt_idx').using(
      'btree',
      table.organizationId.asc().nullsLast(),
      table.createdAt.asc().nullsLast()
    ),
    index('Thread_organizationId_idx').using('btree', table.organizationId.asc().nullsLast()),
    index('Thread_organizationId_status_idx').using(
      'btree',
      table.organizationId.asc().nullsLast(),
      table.status.asc().nullsLast()
    ),
    index('Thread_status_idx').using('btree', table.status.asc().nullsLast()),
    index('thread_pagination_idx').using(
      'btree',
      table.organizationId.asc().nullsLast(),
      table.lastMessageAt.desc().nullsFirst(),
      table.id.desc().nullsFirst()
    ),
    index('Thread_inboxId_idx').using('btree', table.inboxId.asc().nullsLast()),
  ]
)

export type ThreadEntity = typeof Thread.$inferSelect
export type CreateThreadInput = typeof Thread.$inferInsert
export type UpdateThreadInput = Partial<CreateThreadInput>
